parameters.functionCode:
// Filter and normalize jobs based on candidate profile
const profile = {
  desired_roles: ['Software Engineer', 'Full Stack Developer', 'Backend Developer'],
  skills: ['JavaScript', 'Python', 'Node.js', 'React', 'SQL'],
  preferred_job_type: 'remote',
  salary_min: 80000
};

const allJobs = [];

// Parse The Muse results
museData.forEach(job => {
  allJobs.push({
    source: 'TheMuse',
    title: job.name || '',
    company: job.company?.name || 'Unknown',
    location: job.locations?.map(l => l.name).join(', ') || 'Remote',
    url: job.refs?.landing_page || '',
    description: (job.contents || '').replace(/<[^>]*>/g, '').slice(0, 500)
  });
});

// Parse Remotive results
const remotiveData = $input.all()[1]?.json?.jobs || [];
remotiveData.forEach(job => {
  allJobs.push({
    source: 'Remotive',
    title: job.title || '',
    company: job.company_name || 'Unknown',
    location: job.candidate_required_location || 'Remote',
    url: job.url || '',
    description: (job.description || '').replace(/<[^>]*>/g, '').slice(0, 500)
  });
});

// Parse Adzuna results
const adzunaData = $input.all()[2]?.json?.results || [];
adzunaData.forEach(job => {
  allJobs.push({
    source: 'Adzuna',
    title: job.title || '',
    company: job.company?.display_name || 'Unknown',
    location: job.location?.display_name || 'Unknown',
    url: job.redirect_url || '',
    description: (job.description || '').slice(0, 500)
  });
});

// Filter jobs
const keywords = profile.desired_roles.map(r => r.toLowerCase());
const filtered = allJobs.filter(job => {
  const title = job.title.toLowerCase();
  const desc = job.description.toLowerCase();
  const roleMatch = keywords.some(kw => title.includes(kw) || desc.includes(kw));
  const remoteMatch = job.location.toLowerCase().includes('remote') || 
                      job.location.toLowerCase().includes('anywhere');
  return roleMatch && remoteMatch;
});

return filtered.slice(0, 10).map(job => ({ json: job }));

