=You are a career advisor AI. Evaluate this job for a Software Engineer with 3 years of experience in JavaScript, Python, Node.js, React, and SQL.

Job Title: {{$json.title}}
Company: {{$json.company}}
Location: {{$json.location}}
Description: {{$json.description}}

Respond ONLY in JSON format: {"score": <0-100>, "paragraph": "<tailored cover letter paragraph, 2-3 sentences>"}

parameters.functionCode:
// Combine job data with AI evaluation results
const job = $input.item.json;
let aiResult = { score: 50, paragraph: '' };

try {
  const aiContent = job.message?.content || job.choices?.[0]?.message?.content || '{}';
  aiResult = JSON.parse(aiContent);
} catch (e) {
  // Use defaults if parsing fails
}

const coverLetter = `Dear Hiring Manager,

I am excited to apply for the ${job.title} position at ${job.company}. With 3 years of experience in software development and expertise in JavaScript, Python, and Node.js, I am confident I can make a meaningful contribution to your team.

${aiResult.paragraph || ''}

Thank you for your time and consideration. I look forward to discussing this opportunity further.

Best regards,
Your Name`;

return [{
  json: {
    ...job,
    ai_score: aiResult.score || 50,
    cover_letter: coverLetter,
    should_apply: (aiResult.score || 50) >= 60
  }
}];

// Aggregate all qualified applications for the report
const items = $input.all();
const applications = items.map(item => ({
  title: item.json.title,
  company: item.json.company,
  location: item.json.location,
  url: item.json.url,
  source: item.json.source,
  score: item.json.ai_score
}));

return [{
  json: {
    date: new Date().toISOString().split('T')[0],
    total_applications: applications.length,
    applications
  }
}];
